import{_ as o,o as e,c as a,ag as i}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"Login & PIN","description":"","frontmatter":{},"headers":[],"relativePath":"guide/login.md","filePath":"guide/login.md","lastUpdated":1776620726000}'),r={name:"guide/login.md"};function n(s,t,l,d,h,u){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="login-pin" tabindex="-1">Login &amp; PIN <a class="header-anchor" href="#login-pin" aria-label="Permalink to &quot;Login &amp; PIN&quot;">​</a></h1><h2 id="first-login" tabindex="-1">First login <a class="header-anchor" href="#first-login" aria-label="Permalink to &quot;First login&quot;">​</a></h2><ol><li>Open <strong>Fateh HR</strong>.</li><li>You&#39;re on the <strong>Welcome</strong> screen.</li><li>Enter your <strong>work email</strong> (the one HR registered).</li><li>Enter your <strong>password</strong>.</li><li>Tap the <strong>eye icon</strong> in the password field if you want to check what you typed.</li><li>Tap <strong>Continue</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>After your first successful login, your email is remembered. Next time you reach this screen, the email field is pre-filled and the keyboard lands directly on the <strong>password</strong> field — one less tap.</p></div><h3 id="that-email-or-password-didn-t-match" tabindex="-1">&quot;That email or password didn&#39;t match&quot; <a class="header-anchor" href="#that-email-or-password-didn-t-match" aria-label="Permalink to &quot;&quot;That email or password didn&#39;t match&quot;&quot;">​</a></h3><p>If you see this message:</p><ul><li><strong>Check for typos</strong> in the email (common: <code>.com</code> vs <code>.in</code>, missing dot)</li><li><strong>Check the password</strong> — tap the eye icon to see what you typed</li><li>Caps Lock / autocaps on mobile can change the case of characters</li><li>If it still fails, ask HR to <strong>reset your password</strong> from the ERPNext Desk</li></ul><h2 id="set-your-pin" tabindex="-1">Set your PIN <a class="header-anchor" href="#set-your-pin" aria-label="Permalink to &quot;Set your PIN&quot;">​</a></h2><p>Right after your first login, you&#39;re asked to set a 4–6 digit PIN.</p><ol><li>Tap the digits on the keypad to build your PIN.</li><li>You can use <strong>4, 5, or 6 digits</strong>.</li><li>Tap <strong>⌫</strong> to delete a digit.</li><li>Once you have at least 4 digits, tap <strong>Save PIN</strong>.</li></ol><p>This PIN is what you&#39;ll enter every time you open the app, instead of your full password. Think of it as a quick unlock for day-to-day use.</p><div class="warning custom-block"><p class="custom-block-title">Choose something you&#39;ll remember</p><p>You can&#39;t recover a forgotten PIN from inside the app. If you forget it, tap <strong>&quot;Forgot PIN&quot;</strong> on the PIN screen → you&#39;ll be logged out and have to sign in with your password again, then set a new PIN.</p></div><h3 id="good-pin-bad-pin" tabindex="-1">Good PIN, bad PIN <a class="header-anchor" href="#good-pin-bad-pin" aria-label="Permalink to &quot;Good PIN, bad PIN&quot;">​</a></h3><table tabindex="0"><thead><tr><th>✅ Good</th><th>❌ Avoid</th></tr></thead><tbody><tr><td>A memorable 4–6 digit sequence</td><td><code>1234</code>, <code>0000</code>, <code>1111</code></td></tr><tr><td>Your own, not shared</td><td>The year you joined (HR knows it)</td></tr><tr><td>Different from other apps</td><td>Same PIN as your SIM lock</td></tr></tbody></table><h2 id="after-pin-setup" tabindex="-1">After PIN setup <a class="header-anchor" href="#after-pin-setup" aria-label="Permalink to &quot;After PIN setup&quot;">​</a></h2><p>Immediately after saving, you&#39;ll see a <strong>prompt</strong> asking if you&#39;d like to use Face / Touch / Fingerprint unlock. See <a href="/guide/biometric">Biometric unlock</a> — strongly recommended if your phone supports it.</p><p>If you skip this, you can still enable it later (it just asks you again after your next successful PIN unlock).</p><h2 id="day-to-day-unlocking-the-app" tabindex="-1">Day-to-day: unlocking the app <a class="header-anchor" href="#day-to-day-unlocking-the-app" aria-label="Permalink to &quot;Day-to-day: unlocking the app&quot;">​</a></h2><p>From day two onwards, opening the app shows the <strong>PIN screen</strong> directly — not the login form.</p><p><strong>If you enabled biometric:</strong> the fingerprint / face prompt appears automatically. Touch the sensor or look at the screen → straight to the home screen.</p><p><strong>If you didn&#39;t:</strong> type your PIN and tap <strong>Unlock</strong>.</p><p>Your session stays &quot;unlocked&quot; for about 2 hours of activity. After that the PIN / biometric is asked again.</p><h2 id="too-many-wrong-pin-attempts" tabindex="-1">Too many wrong PIN attempts <a class="header-anchor" href="#too-many-wrong-pin-attempts" aria-label="Permalink to &quot;Too many wrong PIN attempts&quot;">​</a></h2><p>If you get the PIN wrong <strong>5 times in a row</strong>, the app locks you out and takes you back to the login screen. You&#39;ll need to sign in with your full password again, then set a fresh PIN.</p><h2 id="forgot-pin" tabindex="-1">Forgot PIN <a class="header-anchor" href="#forgot-pin" aria-label="Permalink to &quot;Forgot PIN&quot;">​</a></h2><p>On the PIN screen, tap <strong>&quot;Forgot PIN&quot;</strong>.</p><p>This clears your local session and returns you to the login screen. Sign in with your password to pick a new PIN.</p><p>Your data (check-ins, leave requests, etc) stays safe on the server — this only affects the local unlock credential.</p><h2 id="changing-your-pin" tabindex="-1">Changing your PIN <a class="header-anchor" href="#changing-your-pin" aria-label="Permalink to &quot;Changing your PIN&quot;">​</a></h2><p>Right now, changing the PIN means:</p><ol><li>Tap <strong>Forgot PIN</strong> on the PIN screen</li><li>Log in with your password</li><li>Set a new PIN when prompted</li></ol><p>(A dedicated &quot;Change PIN&quot; option inside the app is on our roadmap.)</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/biometric">Enable biometric unlock</a></li><li><a href="/guide/check-in">Your first check-in</a></li></ul>',34)])])}const g=o(r,[["render",n]]);export{c as __pageData,g as default};
